  'type' => 'function',
  'function' => 
  array (
    'name' => 'web_monitor',
    'description' => 'Periodically fetch a web page URL, extract its readable text content, diff against the last snapshot stored in SQLite, and report what changed. Like feed_watcher but for arbitrary HTML pages — uses DOMDocument/DOMXPath to strip navigation, scripts, and styles before extracting meaningful content. Computes line-level diffs (additions/removals) between snapshots. Stores full content state in SQLite for cross-session persistence. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
