          'type' => 'string',
          'description' => 'SQLite database filename (stored in workspace). Default: \'web_monitor.sqlite\'.',
        ),
        'timeout' => 
        array (
          'type' => 'integer',
          'description' => 'Timeout in seconds (5-30, default: 20).',
        ),
        'max_changes' => 
        array (
          'type' => 'integer',
          'description' => 'Maximum diff lines to report (10-200, default: 50).',
        ),
        'force_refresh' => 
        array (
          'type' => 'boolean',
          'description' => 'If true, store the current content as the new baseline without reporting diff. Default: false.',
        ),
        'selector' => 
        array (
